    "text_content": "Exemplo: Sun, 10 Sep 2017 19:43:31 UTC\", \"required\": false, \"schema\": { \"type\": \"string\", \"pattern\": \"^(Mon|Tue|Wed|Thu|Fri|Sat|Sun), \\\\d{2} (Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec) \\\\d{4} \\\\d{2}:\\\\d{2}:\\\\d{2} (GMT|UTC)$\", \"minLength\": 29, \"maxLength\": 29 } }, { \"name\": \"x-fapi-customer-ip-address\", \"in\": \"header\", \"description\": \"O endereço IP do usuário se estiver atualmente logado com o receptor.\", \"required\": false, \"schema\": { \"type\": \"string\", \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"minLength\": 1, \"maxLength\": 100 } }, { \"name\": \"x-fapi-interaction-id\", \"in\": \"header\", \"description\": \"Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response. Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta.",
