    "id": "payments_5.0.0_PATCH_pix_payments_paymentId_chunk_17_d1be16dd",
    "text_content": "Deve ser preenchido de forma completa, por exemplo: x-v : 1.0.2.\", \"type\": \"string\", \"pattern\": \"^\\\\d+\\\\.\\\\d+\\\\.\\\\d+$\", \"example\": \"1.0.0\" } } }, \"content\": { \"application/jwt\": { \"schema\": { \"type\": \"object\", \"required\": [ \"data\", \"links\", \"meta\" ], \"properties\": { \"data\": { \"type\": \"object\", \"description\": \"Objeto contendo dados do pagamento e da conta do recebedor (creditor).\", \"required\": [ \"paymentId\", \"endToEndId\", \"consentId\", \"creationDateTime\", \"statusUpdateDateTime\", \"status\", \"localInstrument\", \"payment\", \"creditorAccount\", \"cnpjInitiator\", \"debtorAccount\", \"cancellation\" ], \"properties\": { \"paymentId\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 100, \"pattern\": \"^[a-zA-Z0-9][a-zA-Z0-9\\\\-]{0,99}$\", \"example\": \"TXpRMU9UQTROMWhZV2xSU1FUazJSMDl\", \"description\": \"Código ou identificador único informado pela instituição detentora da conta para representar\\na iniciação de pagamento individual. O `paymentId` deve ser diferente do `endToEndId`.\\nEste é o identificador que deverá ser utilizado na consulta ao status da iniciação de pagamento efetuada.\\n\" }, \"endToEndId\": { \"type\": \"string\", \"minLength\": 32, \"maxLength\": 32, \"pattern\": \"^([E])([0-9A-Z]{8})([0-9]{4})(0[1-9]|1[0-2])(0[1-9]|[1-2][0-9]|3[0-1])(2[0-3]|[01][0-9])([0-5][0-9])([a-zA-Z0-9]{11})$\", \"example\": \"E9040088820210128000800123873170\", \"description\": \"Trata-se de um identificador único, gerado na instituição iniciadora de pagamento e recebido na instituição detentora de conta, permeando toda a jornada do pagamento Pix.\\n\\n[Restrição] A detentora deve obrigatoriamente retornar o campo Com o mesmo valor recebido da iniciadora.\\n\" }, \"consentId\": { \"type\": \"string\", \"maxLength\": 256, \"pattern\": \"^urn:[a-zA-Z0-9][a-zA-Z0-9\\\\-]{0,31}:[a-zA-Z0-9()+,\\\\-.:=@;$_!",
