    "id": "payments_5.0.0_PATCH_pix_payments_paymentId_chunk_44_d4b94987",
    "text_content": "1-9])T(?:[01]\\\\d|2[0123]):(?:[012345]\\\\d):(?:[012345]\\\\d)Z$\", \"example\": \"2021-05-21T08:30:00Z\" }, \"cancelledBy\": { \"type\": \"object\", \"description\": \"Informação relacionada ao usuário pagador que solicitou o cancelamento do pagamento.\", \"required\": [ \"document\" ], \"properties\": { \"document\": { \"type\": \"object\", \"description\": \"Objeto que consolida os dados do documento do usuário que solicitou o cancelamento.\", \"required\": [ \"identification\", \"rel\" ], \"properties\": { \"identification\": { \"type\": \"string\", \"maxLength\": 11, \"description\": \"Número do documento do usuário pagador responsável pelo cancelamento do pagamento.\", \"example\": \"11111111111\", \"pattern\": \"^\\\\d{11}$\" }, \"rel\": { \"type\": \"string\", \"maxLength\": 3, \"description\": \"Tipo do documento do usuário pagador responsável pelo cancelamento do pagamento.\", \"example\": \"CPF\", \"pattern\": \"^[A-Z]{3}$\" } } } } } } }, \"debtorAccount\": { \"type\": \"object\", \"description\": \"Objeto que contém a identificação da conta de origem do pagador. \\nAs informações quanto à conta de origem do pagador poderão ser trazidas no consentimento para a detentora, caso a iniciadora tenha coletado essas informações do cliente. Do contrário, será coletada na detentora e trazida para a iniciadora como resposta à criação do pagamento.\\n\", \"required\": [ \"ispb\", \"number\", \"accountType\" ], \"properties\": { \"ispb\": { \"type\": \"string\", \"minLength\": 8, \"maxLength\": 8, \"pattern\": \"^[0-9A-Z]{8}$\", \"example\": \"123456BC\", \"description\": \"Deve ser preenchido com o ISPB (Identificador do Sistema de Pagamentos Brasileiros) do participante do SPI (Sistema de pagamentos instantâneos) somente com números.\\n\" }, \"issuer\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 4, \"pattern\": \"^[0-9]{1,4}$\", \"example\": \"1774\", \"description\": \"Código da Agência emissora da conta sem dígito. \\n(Agência é a dependência destinada ao atendimento aos clientes, ao público em geral e aos associados de cooperativas de crédito, \\nno exercício de atividades da instituição, não podendo ser móvel ou transitória).\\n\\n[Restrição] Preenchimento obrigatório para os seguintes tipos de conta: CACC (CONTA_DEPOSITO_A_VISTA) e SVGS (CONTA_POUPANCA).\\n\" }, \"number\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 20, \"pattern\": \"^[0-9]{1,20}$\", \"example\": \"1234567890\", \"description\": \"Deve ser preenchido com o número da conta transacional do usuário pagador, com dígito verificador (se este existir), \\nse houver valor alfanumérico, este deve ser convertido para 0.\\n\" }, \"accountType\": \"[Circular Reference]\" } }, \"authorisationFlow\": { \"type\": \"string\", \"enum\": [ \"HYBRID_FLOW\", \"CIBA_FLOW\", \"FIDO_FLOW\" ], \"example\": \"HYBRID_FLOW\", \"description\": \"Campo condicional utilizado para identificar o fluxo de autorização em que o pagamento foi solicitado.\\n\\n[Restrição] Se CIBA ou FIDO, preenchimento obrigatório.",
    "title": "Cancelar iniciação de pagamento.",
    "url": "/pix/payments/{paymentId}",
