    "id": "payments_5.0.0_PATCH_pix_payments_paymentId_chunk_62_5a536c0a",
    "text_content": "A iniciadora deve acatar o valor gerado pelo detentor e recebido na resposta.\\n\", \"schema\": \"[Circular Reference]\" } } }, \"422\": { \"description\": \"Seguir as orientações presentes na descrição deste endpoint.\", \"content\": { \"application/jwt\": { \"schema\": { \"type\": \"object\", \"required\": [ \"errors\" ], \"properties\": { \"errors\": { \"type\": \"array\", \"minItems\": 1, \"maxItems\": 9, \"items\": { \"type\": \"object\", \"required\": [ \"code\", \"title\", \"detail\" ], \"properties\": { \"code\": { \"type\": \"string\", \"enum\": [ \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"ERRO_IDEMPOTENCIA\" ], \"example\": \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"description\": \"Códigos de erros previstos na criação da iniciação de pagamento:\\n\\n• PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento não permite cancelamento \\n• ERRO_IDEMPOTENCIA: Conteúdo da mensagem (claim data) diverge do conteúdo associado a esta chave de idempotência (x-idempotency-key).\\n\" }, \"title\": { \"type\": \"string\", \"maxLength\": 255, \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"example\": \"Pagamento não permite cancelamento.\", \"description\": \"Título específico do erro reportado, de acordo com o código enviado:\\n\\n• PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento não permite cancelamento \\n• ERRO_IDEMPOTENCIA: Conteúdo da mensagem (claim data) diverge do conteúdo associado a esta chave de idempotência (x-idempotency-key).\\n\" }, \"detail\": { \"type\": \"string\", \"maxLength\": 2048, \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"example\": \"Pagamento não permite cancelamento.\", \"description\": \"Descrição específica do erro de acordo com o código reportado:\\n\\n• PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento não permite cancelamento \\n• ERRO_IDEMPOTENCIA: Conteúdo da mensagem (claim data) diverge do conteúdo associado a esta chave de idempotência (x-idempotency-key).\\n\" } } } }, \"meta\": \"[Circular Reference]\" } }, \"examples\": { \"Saldo insuficiente\": { \"summary\": \"Saldo insuficiente\", \"value\": { \"errors\": [ { \"code\": \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"title\": \"Pagamento não permite cancelamento\", \"detail\": \"Pagamento não permite cancelamento\" } ], \"meta\": { \"requestDateTime\": \"2021-05-21T08:30:00Z\" } } } } } }, \"headers\": { \"x-fapi-interaction-id\": { \"description\": \"Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response. Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta.",
